def embed_images_as_base64(data, html_file):
    """将图片转换为Base64嵌入"""
    with open(html_file, 'r+', encoding='utf-8') as f:
        content = f.read()
        for url, path in data['image_map'].items():
            if path and os.path.exists(path):
                with open(path, 'rb') as img_file:
                    base64_data = base64.b64encode(img_file.read()).decode()
                    content = content.replace(
                        f'src="{path}"',
                        f'src="data:image/jpeg;base64,{base64_data}"'
                    )
        f.seek(0)
        f.write(content)
        f.truncate()
```

2. 调用方式（在保存HTML后添加）：
```python
